#include <bits/stdc++.h>
using namespace std;

const int N=2e6+10,mod=20100403;

int n,m,fac[N],inv[N];

int quick_mi(int a,int b){
    long long ans=1,base=a;
    while(b){
        if(b&1)
            ans=ans*base%mod;
        base=base*base%mod,b>>=1;
    }
    return ans;
}

int C(int n,int m){
    if(n<0 || m<0 || n<m)
        return 0;
    return 1LL*fac[n]*inv[n-m]%mod*inv[m]%mod;
}

int main(){
    scanf("%d%d",&n,&m);
    fac[0]=1;
    for(int i=1;i<=n+m;i++)
        fac[i]=1LL*fac[i-1]*i%mod;
    inv[n+m]=quick_mi(fac[n+m],mod-2);
    for(int i=n+m-1;i>=0;i--)
        inv[i]=1LL*inv[i+1]*(i+1)%mod;
    printf("%d",(C(n+m,n)-C(n+m,n+1)+mod)%mod);
    return 0;
}
